@register.simple_tag
def icon(name, cls="", style="", size=16):
    """Render an inline SVG icon in place of the bootstrap-icons webfont.
    Usage: {% icon "arrow-right" cls="me-1" style="color:red" %}
    """
    path_data = ICONS.get(name)
    if not path_data:
        return ""
    class_attr = f' class="{cls}"' if cls else ""
    merged_style = "vertical-align:-0.125em"
    if style:
        merged_style = f"{merged_style};{style}"
    svg = (
        f'<svg xmlns="http://www.w3.org/2000/svg" width="{size}" height="{size}" '
        f'fill="currentColor"{class_attr} style="{merged_style}" viewBox="0 0 16 16">{path_data}</svg>'
    )
    return mark_safe(svg)
